mapper.select:
select a.ID, a.RATE_ITEM_CODE, a.RATE_NAME, a.RATE, a.TAX_RATE, a.BILL_DATE, a.RATE_ID, a.VOYAGE_ID, a.SHIP_VOYAGE, a.BILL_QUANTITY, a.BILL_QUANTITY2, a.AMOUNT_MONEY, a.TAX_AMOUNT, a.TRUST_ORDER_ID, a.CREATE_BY, a.CREATE_BY_NAME, a.CREATE_TIME, a.UPDATE_BY, a.UPDATE_TIME, a.UPDATE_BY_NAME, a.CUSTOMER_ID, a.STATEMENT_BY, a.STATEMENT_TIME, a.STATEMENT_BY_NAME, b.CUSTOMER_NAME, CASE WHEN a.STATEMENT_ID IS NOT NULL THEN (CASE WHEN TO_NUMBER(TCS.STATUS) >= 31 THEN TO_NUMBER(TCS.STATUS) ELSE TO_NUMBER(a.STATUS) END) ELSE TO_NUMBER(a.STATUS) END AS STATUS, a.company_id, a.company_name, TBR.PROCESS_NAME, TBR.PROCESS_CODE, TCS.STATEMENT_NO, TBCI.CARGO_NAME, A.REJECT_BY, A.REJECT_BY_NAME, A.REJECT_TIME, A.REJECT_REASON from T_MISC_BILLING a inner join T_BUS_CUSTOMER b on a.CUSTOMER_ID=b.id LEFT JOIN M_FEE_ITEM MFI ON MFI.ITEM_CD = a.RATE_ITEM_CODE LEFT JOIN T_BUS_RATE TBR ON a.RATE_ID = TBR.ID LEFT JOIN T_COST_STATEMENT TCS ON TCS.ID = a.STATEMENT_ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TDSI.ID = a.VOYAGE_ID LEFT JOIN T_DIS_SHIPVOYAGE TDS ON TDS.ID = TDSI.SHIPVOYAGE_ID left JOIN T_BUS_CARGO_INFO TBCI ON TBCI.ID = a.CARGO_INFO_ID
MFI.IS_MAIN_INCOME = 1
AND TDS.SHIP_NAME LIKE #{shipName_like}
AND TDSI.VOYAGE LIKE #{voyage_like}
and a.VOYAGE_ID=#{shipvoyageItemId}
and a.CUSTOMER_ID=#{customerId}
AND CASE WHEN a.STATEMENT_ID IS NOT NULL THEN ( CASE WHEN TO_NUMBER( TCS.STATUS ) >= 31 THEN TO_NUMBER( TCS.STATUS ) ELSE TO_NUMBER( a.STATUS ) END ) ELSE TO_NUMBER( a.STATUS ) END =#{status}
and a.RATE_ITEM_CODE=#{rateItemCode}
and TCS.STATEMENT_NO=#{statementNo}
and TBR.PROCESS_CODE=#{processCode}
ORDER BY a.CREATE_TIME DESC

select a.ID, a.RATE_ITEM_CODE, a.RATE_NAME, a.RATE, a.TAX_RATE, a.BILL_DATE, a.RATE_ID, a.VOYAGE_ID, a.SHIP_VOYAGE, a.BILL_QUANTITY, a.BILL_QUANTITY2, a.AMOUNT_MONEY, a.TAX_AMOUNT, a.TRUST_ORDER_ID, a.CREATE_BY, a.CREATE_BY_NAME, a.CREATE_TIME, a.UPDATE_BY, a.UPDATE_TIME, a.UPDATE_BY_NAME, a.CUSTOMER_ID, a.STATEMENT_BY, a.STATEMENT_TIME, a.STATEMENT_BY_NAME, b.CUSTOMER_NAME, CASE WHEN a.STATEMENT_ID IS NOT NULL THEN (CASE WHEN TO_NUMBER(TCS.STATUS) >= 31 THEN TO_NUMBER(TCS.STATUS) ELSE TO_NUMBER(a.STATUS) END) ELSE TO_NUMBER(a.STATUS) END AS STATUS, a.company_id, a.company_name, TBR.PROCESS_NAME, TBR.PROCESS_CODE, TCS.STATEMENT_NO, TBCI.CARGO_NAME, A.REJECT_BY, A.REJECT_BY_NAME, A.REJECT_TIME, A.REJECT_REASON from T_MISC_BILLING a inner join T_BUS_CUSTOMER b on a.CUSTOMER_ID=b.id LEFT JOIN M_FEE_ITEM MFI ON MFI.ITEM_CD = a.RATE_ITEM_CODE LEFT JOIN T_BUS_RATE TBR ON a.RATE_ID = TBR.ID LEFT JOIN T_COST_STATEMENT TCS ON TCS.ID = a.STATEMENT_ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TDSI.ID = a.VOYAGE_ID LEFT JOIN T_DIS_SHIPVOYAGE TDS ON TDS.ID = TDSI.SHIPVOYAGE_ID left JOIN T_BUS_CARGO_INFO TBCI ON TBCI.ID = a.CARGO_INFO_ID
MFI.IS_MAIN_INCOME = 1
AND TDS.SHIP_NAME LIKE #{shipName_like}
AND TDSI.VOYAGE LIKE #{voyage_like}
and a.VOYAGE_ID=#{shipvoyageItemId}
and a.CUSTOMER_ID=#{customerId}
AND CASE WHEN a.STATEMENT_ID IS NOT NULL THEN ( CASE WHEN TO_NUMBER( TCS.STATUS ) >= 31 THEN TO_NUMBER( TCS.STATUS ) ELSE TO_NUMBER( a.STATUS ) END ) ELSE TO_NUMBER( a.STATUS ) END =#{status}
and a.RATE_ITEM_CODE=#{rateItemCode}
and TCS.STATEMENT_NO=#{statementNo}
and TBR.PROCESS_CODE=#{processCode}
ORDER BY a.CREATE_TIME DESC

select TBR.PROCESS_NAME, TBR.PROCESS_CODE, TBR.MEASUREMENT_UNIT_CODE1 UNIT_CODE, MDD.DICT_LABEL UNIT_NAME, TBR.MEASUREMENT_UNIT_CODE2 from T_BUS_RATE TBR LEFT JOIN M_DICT_DATA MDD ON MDD.DICT_TYPE = 'UNIT' AND TBR.MEASUREMENT_UNIT_CODE1 = MDD.DICT_VALUE
TBR.ID = #{rateId}
group by TBR.PROCESS_NAME, TBR.PROCESS_CODE, TBR.MEASUREMENT_UNIT_CODE1, MDD.DICT_LABEL, TBR.MEASUREMENT_UNIT_CODE2

select a.ID, a.RATE_ITEM_CODE, a.RATE_NAME, a.RATE, a.TAX_RATE, a.BILL_DATE, a.RATE_ID, a.VOYAGE_ID, a.SHIP_VOYAGE, a.BILL_QUANTITY, a.BILL_QUANTITY2, a.AMOUNT_MONEY, a.TAX_AMOUNT, a.TRUST_ORDER_ID, a.CREATE_BY, a.CREATE_BY_NAME, a.CREATE_TIME, a.UPDATE_BY, a.UPDATE_TIME, a.UPDATE_BY_NAME, a.CUSTOMER_ID, b.CUSTOMER_NAME, CASE WHEN a.STATEMENT_ID IS NOT NULL THEN (CASE WHEN TO_NUMBER(TCS.STATUS) >= 31 THEN TO_NUMBER(TCS.STATUS) ELSE TO_NUMBER(a.STATUS) END) ELSE TO_NUMBER(a.STATUS) END AS STATUS, a.company_id, a.company_name, TBR.PROCESS_NAME, TBR.PROCESS_CODE, TCS.STATEMENT_NO, TCS.ID STATEMENT_ID, TCS.STATUS STATEMENT_STATUS, TCS.REJECT_REASON, TCS.REJECT_BY_NAME, TCS.REJECT_TIME from T_MISC_BILLING a inner join T_BUS_CUSTOMER b on a.CUSTOMER_ID=b.id LEFT JOIN M_FEE_ITEM MFI ON MFI.ITEM_CD = a.RATE_ITEM_CODE LEFT JOIN T_BUS_RATE TBR ON a.RATE_ID = TBR.ID LEFT JOIN T_COST_STATEMENT TCS ON TCS.ID = a.STATEMENT_ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TDSI.ID = a.VOYAGE_ID LEFT JOIN T_DIS_SHIPVOYAGE TDS ON TDS.ID = TDSI.SHIPVOYAGE_ID
MFI.ITEM_TYPE_CD = '2' AND MFI.IS_MAIN_INCOME = 1
AND CASE WHEN a.STATEMENT_ID IS NOT NULL THEN (CASE WHEN TO_NUMBER(TCS.STATUS) >= 31 THEN TO_NUMBER(TCS.STATUS) ELSE TO_NUMBER(a.STATUS) END) ELSE TO_NUMBER(a.STATUS) END = #{status,jdbcType=VARCHAR}
AND TDS.SHIP_NAME LIKE #{shipName_like}
AND TDSI.VOYAGE LIKE #{voyage_like}
and a.VOYAGE_ID=#{shipvoyageItemId}
and a.CUSTOMER_ID=#{customerId}
and a.RATE_ITEM_CODE=#{rateItemCode}
and TCS.STATEMENT_NO=#{statementNo}
and TBR.PROCESS_CODE=#{processCode}
ORDER BY a.CREATE_TIME DESC

mapper.update:
update T_MISC_BILLING
set status = #{status,jdbcType=INTEGER} ,
    STATEMENT_BY =#{statementBy},
    STATEMENT_BY_NAME =#{statementByName},
    STATEMENT_TIME =  #{statementTime}
where ID = #{id,jdbcType=BIGINT}

mapper.select:
select a.ID, a.RATE_ITEM_CODE, a.RATE_NAME, a.RATE, a.TAX_RATE, a.BILL_DATE, a.RATE_ID, a.VOYAGE_ID, a.SHIP_VOYAGE, a.BILL_QUANTITY, a.BILL_QUANTITY2, a.AMOUNT_MONEY, a.TAX_AMOUNT, a.TRUST_ORDER_ID, a.CREATE_BY, a.CREATE_BY_NAME, a.CREATE_TIME, a.UPDATE_BY, a.UPDATE_TIME, a.UPDATE_BY_NAME, a.CUSTOMER_ID, b.CUSTOMER_NAME, CASE WHEN a.STATEMENT_ID IS NOT NULL THEN (CASE WHEN TO_NUMBER(TCS.STATUS) >= 40 THEN TO_NUMBER(TCS.STATUS) ELSE TO_NUMBER(a.STATUS) END) ELSE TO_NUMBER(a.STATUS) END AS STATUS, a.company_id, a.company_name, TBR.PROCESS_NAME, TBR.PROCESS_CODE, TCS.STATEMENT_NO from T_MISC_BILLING a inner join T_BUS_CUSTOMER b on a.CUSTOMER_ID=b.id LEFT JOIN M_FEE_ITEM MFI ON MFI.ITEM_CD = a.RATE_ITEM_CODE LEFT JOIN T_BUS_RATE TBR ON a.RATE_ID = TBR.ID LEFT JOIN T_COST_STATEMENT TCS ON TCS.ID = a.STATEMENT_ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TDSI.ID = a.VOYAGE_ID LEFT JOIN T_DIS_SHIPVOYAGE TDS ON TDS.ID = TDSI.SHIPVOYAGE_ID
MFI.IS_MAIN_INCOME = 0
AND TDS.SHIP_NAME LIKE #{shipName_like}
AND TDSI.VOYAGE LIKE #{voyage_like}
and a.VOYAGE_ID=#{shipvoyageItemId}
and a.CUSTOMER_ID=#{customerId}
AND CASE WHEN a.STATEMENT_ID IS NOT NULL THEN ( CASE WHEN TO_NUMBER( TCS.STATUS ) >= 40 THEN TO_NUMBER( TCS.STATUS ) ELSE TO_NUMBER( a.STATUS ) END ) ELSE TO_NUMBER( a.STATUS ) END =#{status}
and a.RATE_ITEM_CODE=#{rateItemCode}
and TCS.STATEMENT_NO=#{statementNo}
and TBR.PROCESS_CODE=#{processCode}
ORDER BY a.CREATE_TIME DESC

select DISTINCT NVL(TDSD.BERTH_NAME,'')
FROM T_DIS_SHIP_DYNAMIC TDSD
where (TDSD.DYNAMIC_TYPE_NAME = '靠泊' OR TDSD.DYNAMIC_TYPE_NAME = '移泊') and TDSD.BERTH_NAME is not null AND TDSD.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId}
